#!/usr/bin/env python3
"""Validate generated scan reports for structure and content."""
from pathlib import Path
import json
import sys

root = Path(__file__).resolve().parents[1]
errors = []

# Validate normalized_scan.json
normalized = root / 'reports' / 'normalized_scan.json'
if not normalized.exists():
    errors.append('missing report: reports/normalized_scan.json')
else:
    try:
        data = json.loads(normalized.read_text())
    except json.JSONDecodeError as exc:
        errors.append(f'reports/normalized_scan.json is not valid JSON: {exc}')
    else:
        if not isinstance(data, dict):
            errors.append('reports/normalized_scan.json: root must be an object')
        else:
            if 'target' not in data:
                errors.append('reports/normalized_scan.json: missing required key "target"')
            if 'ports' not in data:
                errors.append('reports/normalized_scan.json: missing required key "ports"')
            elif not isinstance(data['ports'], list):
                errors.append('reports/normalized_scan.json: "ports" must be a list')
            else:
                for i, port in enumerate(data['ports']):
                    for key in ('protocol', 'port', 'state', 'service'):
                        if key not in port:
                            errors.append(
                                f'reports/normalized_scan.json: port entry {i} missing key "{key}"'
                            )

# Validate port_classification.md
port_class = root / 'reports' / 'port_classification.md'
if not port_class.exists():
    errors.append('missing report: reports/port_classification.md')
else:
    content = port_class.read_text()
    if '| Protocol | Port | Service | Label |' not in content:
        errors.append(
            'reports/port_classification.md: missing expected table header '
            '"| Protocol | Port | Service | Label |"'
        )

# Validate local_scan_report.md
local_report = root / 'reports' / 'local_scan_report.md'
if not local_report.exists():
    errors.append('missing report: reports/local_scan_report.md')
else:
    content = local_report.read_text()
    if '| Protocol | Port | State | Service |' not in content:
        errors.append(
            'reports/local_scan_report.md: missing expected table header '
            '"| Protocol | Port | State | Service |"'
        )

if errors:
    for error in errors:
        print(error, file=sys.stderr)
    sys.exit(1)
print('OK: reports validated')

